// Arbeitnow: paginate up to 10 pages, relaxed client-side filters
const MAX_PAGES = 10;
const DELAY_MS = 5000;
const cutoff = Date.now() - 30*24*60*60*1000;

const titleKw = ['python','backend','back-end','back end','data engineer','data engineering','software engineer','software developer','platform engineer','api developer','developer python','entwickler','softwareentwickler','devops','site reliability','sre','etl','junior developer','junior engineer','flask','django','fastapi','developer','engineer','cloud','infrastructure','programmierer','informatiker','application engineer','system engineer','web developer','webentwickler','it engineer','automation','machine learning','ml engineer','data scientist','data analyst','full stack','fullstack'];
const tagKw = ['python','backend','data','engineering','devops','api','flask','django','fastapi','docker','aws','postgresql','kubernetes','linux','sql','java','node','typescript','go','rust','cloud','azure','gcp','terraform','ci/cd','microservices'];
const locKw = ['hamburg','berlin','germany','remote','deutschland','m\u00fcnchen','munich','frankfurt','k\u00f6ln','cologne','deutsch','d\u00fcsseldorf','hannover','stuttgart','bremen','n\u00fcrnberg','nuremberg','leipzig','dresden','essen','dortmund','bonn','karlsruhe','mannheim','freiburg','heidelberg','europe','eu','dach'];
const engWords = ['the','and','you','we','team','experience','requirements','about','our','will','work','join','role','position'];

function isLikelyEnglish(desc) {
  const sample = (desc||'').substring(0,500).toLowerCase();
  const hits = engWords.filter(w => sample.includes(w)).length;
  return hits >= 3;
}

const allJobs = [];
const seen = new Set();

for (let page = 1; page <= MAX_PAGES; page++) {
  if (page > 1) await new Promise(r => setTimeout(r, DELAY_MS));
  let body;
  try {
    body = await this.helpers.httpRequest({ method: 'GET', url: `https://www.arbeitnow.com/api/job-board-api?page=${page}`, json: true });
  } catch(e) { break; }
  const data = body.data || [];
  if (data.length === 0) break;

  let allOld = true;
  for (const job of data) {
    const created = new Date(job.created_at*1000||job.created_at).getTime();
    if (created > cutoff) allOld = false;

    const t = (job.title||'').toLowerCase();
    const l = (job.location||'').toLowerCase();
    const tags = (job.tags||[]).map(t=>t.toLowerCase());
    const titleMatch = titleKw.some(k=>t.includes(k));
    const tagMatch = tagKw.some(k=>tags.includes(k));
    const locMatch = locKw.some(k=>l.includes(k)) || job.remote;

    // Negative keywords â€” auto-skip obviously irrelevant roles
    const negKw = ['manager','consultant','designer','marketing','sales','recruiter','sap','abap','salesforce','product owner','scrum master','project manager','buchhalter','accounting','finance','legal','rechtsanwalt','jurist','pflege','nurse','arzt','physician','lehrer','teacher','werkstudent','intern','praktikant','trainee','senior director','vp ','vice president','head of','chief'];
    const negMatch = negKw.some(k => t.includes(k));

    if (!negMatch && (titleMatch || tagMatch || locMatch) && created > cutoff) {
      const key = job.slug||job.url||job.title;
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push(job);
      }
    }
  }
  if (allOld) break;
  const lastPage = body.meta?.last_page || MAX_PAGES;
  if (page >= lastPage) break;
}

if (allJobs.length === 0) return [{ json: { _empty: true } }];

return allJobs.map((j, i) => {
  const desc = (j.description||'').substring(0,5000);
  const jobData = {
    source: 'arbeitnow',
    external_id: j.slug||'',
    url: j.url||`https://www.arbeitnow.com/view/${j.slug}`,
    title: j.title||'',
    company: j.company_name||'',
    location: j.location||'',
    description: desc,
    tags: j.tags||[],
    remote: j.remote||false,
    _likely_english: isLikelyEnglish(desc)
  };
  const filterData = JSON.stringify({
    title: jobData.title,
    company: jobData.company,
    location: jobData.location,
    description: desc.substring(0, 3000),
    tags: jobData.tags,
    url: jobData.url,
    _likely_english: jobData._likely_english
  });
  const b64 = Buffer.from(filterData).toString('base64');
  return { json: { ...jobData, _b64: b64, _idx: i } };
});

// Arbeitsagentur: run multiple server-side filtered searches (no detail fetch)
const BASE = 'https://rest.arbeitsagentur.de/jobboerse/jobsuche-service/pc/v4/jobs';
const HEADERS = { 'X-API-Key': 'jobboerse-jobsuche', 'User-Agent': 'Mozilla/5.0', 'Accept': 'application/json' };

const searches = [
  'Python Developer',
  'Backend Engineer',
  'Data Engineer',
  'Software Engineer',
  'Python Entwickler',
  'Software Entwickler',
  'Backend Entwickler',
  'ETL Developer',
  'ETL Entwickler',
  'Cloud Engineer'
];
const commonParams = 'wo=Hamburg&umkreis=200&veroeffentlichtseit=30&pav=false&zeitarbeit=false&size=100';

const seenIds = new Set();
const jobs = [];
const errors = [];

const MAX_PAGES = 3;
for (let i = 0; i < searches.length; i++) {
  for (let page = 1; page <= MAX_PAGES; page++) {
    const url = `${BASE}?was=${encodeURIComponent(searches[i])}&${commonParams}&page=${page}`;
    let body;
    try {
      const raw = await this.helpers.httpRequest({ method: 'GET', url, headers: HEADERS });
      body = typeof raw === 'string' ? JSON.parse(raw) : raw;
    } catch(e) { errors.push({search: searches[i], page, error: e.message || String(e)}); continue; }
    const results = body.stellenangebote || [];
    if (results.length === 0) break;
    for (const s of results) {
      const id = s.refnr || s.titel;
      if (!seenIds.has(id)) {
        seenIds.add(id);
        jobs.push(s);
      }
    }
    const maxPage = body.maxErgebnisse ? Math.ceil(body.maxErgebnisse / 100) : 1;
    if (page >= maxPage) break;
  }
}

if (jobs.length === 0) return [{ json: { _empty: true, _errors: errors, _errorCount: errors.length } }];

return jobs.map((j, i) => {
  const company = typeof j.arbeitgeber === 'object' ? (j.arbeitgeber?.name || '') : (j.arbeitgeber || '');
  const location = j.arbeitsort?.ort || '';
  const region = j.arbeitsort?.region || '';
  const extUrl = j.externeUrl || '';
  const refUrl = j.refnr ? `https://www.arbeitsagentur.de/jobsuche/suche?id=${j.refnr}` : '';
  const url = extUrl || refUrl;
  const desc = `${j.titel || ''} bei ${company} in ${location}${region ? ' (' + region + ')' : ''}. Beruf: ${j.beruf || ''}. Eintrittsdatum: ${j.eintrittsdatum || 'k.A.'}`;
  const jobData = {
    source: 'arbeitsagentur',
    external_id: j.refnr || '',
    url: url,
    title: j.titel || '',
    company: company,
    location: location,
    description: desc,
    tags: [],
    remote: false,
    _likely_english: false
  };
  const filterData = JSON.stringify({
    title: jobData.title,
    company: jobData.company,
    location: jobData.location,
    description: desc,
    tags: jobData.tags,
    url: jobData.url,
    _likely_english: false
  });
  const b64 = Buffer.from(filterData).toString('base64');
  return { json: { ...jobData, _b64: b64, _idx: i } };
});

// Deduplicate merged results by company+title
const all = $input.all().filter(i => !i.json._empty);
const seen = new Set();
const unique = [];

for (const item of all) {
  const job = item.json;
  const key = ((job.company||'') + '|' + (job.title||'')).toLowerCase().trim();
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(job);
  }
}

if (unique.length === 0) return [{ json: { _empty: true } }];
return unique.map((j, i) => ({ json: { ...j, _idx: i } }));

// Filter out already-seen URLs by reading Job URL column from Sheet
let sheetRows;
try { sheetRows = $('Dedup: Read Seen').all(); } catch(e) { sheetRows = []; }
const seen = new Set(sheetRows.map(r => r.json['Job URL']).filter(Boolean));

const jobs = $('Has Results?').all().filter(item => {
  const url = item.json?.url;
  return url && !seen.has(url);
});

// Cap at 80 new items to keep Claude calls manageable
return jobs.length > 0 ? jobs.slice(0, 80) : [{ json: { _empty: true } }];

// Parse filter results and carry forward job data for Generate step
const results = [];
for (const item of $input.all()) {
  const stdout = item.json.stdout || '{}';
  let assessment;
  try {
    assessment = JSON.parse(stdout);
  } catch(e) {
    assessment = { fit_score: 0, decision: 'SKIP', cv_variant: 'software', hard_blockers: ['Claude parse error'], reasoning: stdout.substring(0,200) };
  }

  // Get job data from the matching item in Dedup: Filter by index
  const allDedup = $('Dedup: Filter').all();
  const idx = results.length;
  const jobData = (allDedup[idx] || item).json;

  // Normalize decision: only PASS, MAYBE, or SKIP
  const rawDecision = String(assessment.decision || 'SKIP').trim().toUpperCase();
  const decision = ['PASS','MAYBE','SKIP'].includes(rawDecision) ? rawDecision : 'SKIP';
  const score = Number(assessment.fit_score) || 0;

  results.push({
    json: {
      'Date': new Date().toISOString().slice(0,10),
      'Fetched At': new Date().toISOString().replace('T',' ').slice(0,19) + ' UTC',
      'Source': jobData.source || 'arbeitnow',
      'Company': assessment.company || jobData.company || '',
      'Role': assessment.role || jobData.title || '',
      'Location': assessment.location || jobData.location || '',
      'Score': score,
      'Decision': decision,
      'CV Variant': assessment.cv_variant || 'software',
      'Blockers': (assessment.hard_blockers || []).join('; '),
      'Strong Matches': (assessment.strong_matches || []).join('; '),
      'Reasoning': assessment.reasoning || '',
      'Status': decision === 'SKIP' ? 'skipped' : 'review',
      'Drive Link': '',
      'Job URL': jobData.url || '',
      'Notes': '',
      _assessment: assessment,
      _url: jobData.url || '',
      _description: jobData.description || ''
    }
  });
}
return results;

// Strip internal fields before Sheet logging
return $input.all().map(item => {
  const d = item.json;
  return { json: {
    'Date': d['Date'] || '',
    'Fetched At': d['Fetched At'] || '',
    'Source': d['Source'] || '',
    'Company': d['Company'] || '',
    'Role': d['Role'] || '',
    'Location': d['Location'] || '',
    'Score': d['Score'] || 0,
    'Decision': d['Decision'] || 'SKIP',
    'CV Variant': d['CV Variant'] || 'software',
    'Blockers': d['Blockers'] || '',
    'Strong Matches': d['Strong Matches'] || '',
    'Reasoning': d['Reasoning'] || '',
    'Status': d['Status'] || 'skipped',
    'Drive Link': '',
    'Job URL': d['Job URL'] || '',
    'Notes': d['Notes'] || ''
  }};
});

// Build generate input â€” lightweight, generate.py fetches full posting
return $input.all().map(item => {
  const d = item.json;
  const generateInput = JSON.stringify({
    cv_variant: d['CV Variant'] || 'software',
    job: {
      title: d['Role'] || '',
      company: d['Company'] || '',
      location: d['Location'] || '',
      url: d['Job URL'] || ''
    },
    assessment: {
      company: d._assessment?.company || '',
      role: d._assessment?.role || '',
      fit_score: d._assessment?.fit_score || 0,
      decision: d._assessment?.decision || '',
      cv_variant: d._assessment?.cv_variant || 'software',
      strong_matches: d._assessment?.strong_matches || [],
      soft_gaps: d._assessment?.soft_gaps || [],
      reasoning: (d._assessment?.reasoning || '').substring(0, 500)
    }
  });
  const b64 = Buffer.from(generateInput).toString('base64');
  return {
    json: {
      ...d,
      _generateB64: b64
    }
  };
});

// Parse generate output and merge with filter data for file writing
const results = [];
const passItems = $('Is PASS?').all();

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const passItem = passItems[i] || {};
  const stdout = item.json.stdout || '{}';
  let generated;
  try {
    generated = JSON.parse(stdout);
  } catch(e) {
    generated = { error: 'Failed to parse generate output', raw: stdout.substring(0,200) };
  }

  const filterData = passItem.json || {};

  // Build input for write_output.py
  const writeObj = {
    company: filterData['Company'] || '',
    title: filterData['Role'] || '',
    location: filterData['Location'] || '',
    url: filterData['Job URL'] || '',
    description: filterData._description || '',
    tailored_cv_html: generated.tailored_cv_html || '',
    cover_letter_html: generated.cover_letter_html || '',
    cover_letter_text: generated.cover_letter_text || '',
    assessment: filterData._assessment || {},
    tailoring_notes: generated.tailoring_notes || ''
  };
  const writeB64 = Buffer.from(JSON.stringify(writeObj)).toString('base64');

  results.push({
    json: {
      ...filterData,
      _writeB64: writeB64,
      _generated: generated,
      _hasError: !!generated.error
    }
  });
}
return results;

// Prepare data for Drive upload and Sheet logging
const results = [];
const genItems = $('Generate: Parse').all();

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const genItem = genItems[i] || {};
  const filterData = genItem.json || {};
  let writeResult;
  try {
    writeResult = JSON.parse(item.json.stdout || '{}');
  } catch(e) {
    writeResult = { outputDir: '', folderName: '' };
  }

  const hasError = filterData._hasError || !!writeResult.error;

  results.push({
    json: {
      'Date': filterData['Date'] || new Date().toISOString().slice(0,10),
      'Source': filterData['Source'] || '',
      'Company': filterData['Company'] || '',
      'Role': filterData['Role'] || '',
      'Location': filterData['Location'] || '',
      'Score': filterData['Score'] || 0,
      'Decision': 'PASS',
      'CV Variant': filterData['CV Variant'] || 'software',
      'Blockers': filterData['Blockers'] || '',
      'Strong Matches': filterData['Strong Matches'] || '',
      'Reasoning': filterData['Reasoning'] || '',
      'Status': hasError ? 'review' : 'generated',
      'Drive Link': '',
      'Job URL': filterData['Job URL'] || '',
      'Notes': hasError ? 'Generate failed â€” review manually' : (filterData._generated?.tailoring_notes || ''),
      _outputDir: writeResult.outputDir || '',
      _folderName: writeResult.folderName || '',
      _hasError: hasError
    }
  });
}
return results;

// Prepare file upload list â€” emit one item per file with binary data
const item = $input.all()[0];
const prepItem = $('Has Files?').all()[0];
const folderId = item.json.id; // Google Drive folder ID from previous node
const outputDir = prepItem.json._outputDir;

const files = ['cv.html', 'cover_letter.html', 'cover_letter.txt', 'assessment.json', 'job.json'];
const results = [];

for (const f of files) {
  const filePath = outputDir + '/' + f;
  try {
    const fs = require('fs');
    const content = fs.readFileSync(filePath);
    const binary = await this.helpers.prepareBinaryData(content, f);
    results.push({
      json: {
        fileName: f,
        folderId: folderId,
        folderUrl: `https://drive.google.com/drive/folders/${folderId}`,
        ...prepItem.json
      },
      binary: { data: binary }
    });
  } catch(e) {
    // Skip files that don't exist
  }
}
return results;

// After all files uploaded, emit one item per job for Sheet logging
const allUploaded = $input.all();
if (allUploaded.length === 0) return [];

// Group by folder â€” all files share the same folderUrl
const first = allUploaded[0].json;
return [{
  json: {
    'Date': first['Date'] || '',
    'Fetched At': first['Fetched At'] || '',
    'Source': first['Source'] || '',
    'Company': first['Company'] || '',
    'Role': first['Role'] || '',
    'Location': first['Location'] || '',
    'Score': first['Score'] || 0,
    'Decision': 'PASS',
    'CV Variant': first['CV Variant'] || 'software',
    'Blockers': first['Blockers'] || '',
    'Strong Matches': first['Strong Matches'] || '',
    'Reasoning': first['Reasoning'] || '',
    'Status': 'generated',
    'Drive Link': first.folderUrl || '',
    'Job URL': first['Job URL'] || '',
    'Notes': first['Notes'] || ''
  }
}];

// Log PASS items that had errors (no Drive upload)
const items = $input.all();
return items.map(item => {
  const d = item.json;
  return {
    json: {
      'Date': d['Date'] || '',
      'Fetched At': d['Fetched At'] || '',
      'Source': d['Source'] || '',
      'Company': d['Company'] || '',
      'Role': d['Role'] || '',
      'Location': d['Location'] || '',
      'Score': d['Score'] || 0,
      'Decision': 'PASS',
      'CV Variant': d['CV Variant'] || 'software',
      'Blockers': d['Blockers'] || '',
      'Strong Matches': d['Strong Matches'] || '',
      'Reasoning': d['Reasoning'] || '',
      'Status': 'review',
      'Drive Link': '',
      'Job URL': d['Job URL'] || '',
      'Notes': d['Notes'] || 'Generate/upload failed'
    }
  };
});
